      ghost: "bg-transparent hover:bg-slate-800 text-slate-300"
    };

    return (
      <button className={`${baseStyles} ${variants[variant]} ${className}`} {...props}>
        {children}
      </button>
    );
};

export const ProgressBar: React.FC<{ value: number; max: number; color?: string; label?: string }> = ({ value, max, color = "bg-emerald-500", label }) => {
  const percentage = Math.min(100, Math.max(0, (value / max) * 100));

  return (
    <div className="w-full">
      {label && (
        <div className="flex justify-between mb-1 text-xs font-medium text-slate-400">
          <span>{label}</span>
          <span>{value} / {max}</span>
        </div>
      )}
      <div className="w-full bg-slate-900 rounded-full h-3 border border-slate-700 overflow-hidden">
        <div 
          className={`h-full rounded-full transition-all duration-500 ease-out ${color} relative`} 
          style={{ width: `${percentage}%` }}
        >
          <div className="absolute inset-0 bg-white/20 animate-pulse"></div>
        </div>
      </div>
    </div>
  );
};

