import React, { useState } from 'react';
import { Exercise, ExerciseType } from '../types';
import { Card, Button } from '../components/Shared';
import { Trash2, Plus, Play, Dumbbell, Timer } from 'lucide-react';

interface CustomWorkoutProps {
  exercises: Exercise[];
  setExercises: (exercises: Exercise[]) => void;
  onStartSession: () => void;
}

export const CustomWorkout: React.FC<CustomWorkoutProps> = ({ exercises, setExercises, onStartSession }) => {
  const [newExercise, setNewExercise] = useState<Partial<Exercise>>({
    name: '',
    type: 'REPS',
    target: 10,
    sets: 3
  });

  const handleAddExercise = () => {
    if (!newExercise.name || !newExercise.target || !newExercise.sets) return;

    const exercise: Exercise = {
      id: crypto.randomUUID(),
      name: newExercise.name,
      type: newExercise.type as ExerciseType,
      target: Number(newExercise.target),
      sets: Number(newExercise.sets),
    };

    setExercises([...exercises, exercise]);
    setNewExercise({ name: '', type: 'REPS', target: 10, sets: 3 });
  };

  const handleRemoveExercise = (id: string) => {
    setExercises(exercises.filter(e => e.id !== id));
  };

  const canStart = exercises.length >= 5;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-rpg font-bold text-white">Custom Workout Routine</h2>
        <div className="text-slate-400 text-sm">
          {exercises.length} / 5 Required Exercises
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Form */}
        <Card title="Add New Exercise" className="lg:col-span-1 h-fit">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">Exercise Name</label>
              <input 
                type="text" 
                value={newExercise.name}
                onChange={(e) => setNewExercise({...newExercise, name: e.target.value})}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white focus:border-quest-gold outline-none"
                placeholder="e.g. Push Ups"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Type</label>
                <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-700">
                  <button 
                    onClick={() => setNewExercise({...newExercise, type: 'REPS'})}
                    className={`flex-1 text-xs py-1 rounded ${newExercise.type === 'REPS' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}
                  >
                    Reps
                  </button>
                  <button 
                    onClick={() => setNewExercise({...newExercise, type: 'MINUTES'})}
                    className={`flex-1 text-xs py-1 rounded ${newExercise.type === 'MINUTES' ? 'bg-slate-700 text-white' : 'text-slate-500'}`}
                  >
                    Mins
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Sets</label>
                <input 
                  type="number" 
                  min="1"
                  max="10"
                  value={newExercise.sets}
                  onChange={(e) => setNewExercise({...newExercise, sets: parseInt(e.target.value)})}
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white outline-none"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                {newExercise.type === 'REPS' ? 'Repetitions' : 'Minutes'}
              </label>
              <input 
                type="number" 
                min="1"
                value={newExercise.target}
                onChange={(e) => setNewExercise({...newExercise, target: parseInt(e.target.value)})}
                className="w-full bg-slate-900 border border-slate-700 rounded-lg p-2 text-white outline-none"
              />
            </div>

            <Button onClick={handleAddExercise} className="w-full" disabled={!newExercise.name}>
              <Plus className="w-4 h-4" /> Add to Routine
            </Button>
          </div>
        </Card>

        {/* List */}
        <div className="lg:col-span-2 space-y-4">
          {exercises.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-slate-700 rounded-xl text-slate-500">
              <Dumbbell className="w-12 h-12 mb-4 opacity-50" />
              <p>Your workout scroll is empty.</p>
              <p className="text-sm">Add exercises to build your quest.</p>
            </div>
          ) : (
            <div className="space-y-2">
              {exercises.map((ex, idx) => (
                <div key={ex.id} className="bg-slate-800 border border-slate-700 p-4 rounded-lg flex items-center justify-between group hover:border-slate-500 transition-colors">
                  <div className="flex items-center gap-4">
                    <div className="w-8 h-8 rounded-full bg-slate-900 flex items-center justify-center text-slate-400 font-bold text-sm border border-slate-700">
                      {idx + 1}
                    </div>
                    <div>
                      <h4 className="font-bold text-white">{ex.name}</h4>
                      <div className="flex gap-4 text-xs text-slate-400 mt-1">
                        <span className="flex items-center gap-1">
                          {ex.type === 'REPS' ? <Dumbbell className="w-3 h-3"/> : <Timer className="w-3 h-3"/>}
                          {ex.target} {ex.type === 'REPS' ? 'Reps' : 'Mins'}
                        </span>
                        <span>{ex.sets} Sets</span>
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={() => handleRemoveExercise(ex.id)}
                    className="p-2 text-slate-500 hover:text-red-500 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          )}

          <div className="mt-8 pt-6 border-t border-slate-700">
            <Button 
              onClick={onStartSession} 
              disabled={!canStart} 
              className={`w-full py-4 text-lg ${canStart ? 'animate-pulse' : ''}`}
            >
              <Play className="w-5 h-5" />
              {canStart ? 'Start Workout Session' : `Add ${5 - exercises.length} more exercises to start`}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Exercise, ExerciseType } from '../types';
import { Card, Button, ProgressBar } from '../components/Shared';
import { Play, Pause, RotateCcw, CheckCircle, ArrowRight, ShieldCheck } from 'lucide-react';

interface ActiveSessionProps {
  exercises: Exercise[];
  onComplete: (durationMinutes: number) => void;
  onCancel: () => void;
}

export const ActiveSession: React.FC<ActiveSessionProps> = ({ exercises, onComplete, onCancel }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [currentSet, setCurrentSet] = useState(1);
  const [timer, setTimer] = useState(0); // For workout duration
  const [isActive, setIsActive] = useState(true);

  // Exercise Timer (for MINUTES type)
  const [exerciseTimer, setExerciseTimer] = useState(0);
  const [isExerciseTimerRunning, setIsExerciseTimerRunning] = useState(false);

  const currentExercise = exercises[currentIndex];
  const isTimeBased = currentExercise.type === 'MINUTES';
  const targetTimeSeconds = isTimeBased ? currentExercise.target * 60 : 0;

  useEffect(() => {
    let interval: any;
    if (isActive) {
      interval = setInterval(() => {
        setTimer(t => t + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isActive]);

  useEffect(() => {
    let interval: any;
    if (isExerciseTimerRunning && isTimeBased && exerciseTimer > 0) {
      interval = setInterval(() => {
        setExerciseTimer(t => {
          if (t <= 1) {
            setIsExerciseTimerRunning(false);
            // Auto complete set logic could go here, but let's require manual click
            return 0;
          }
          return t - 1;
        });
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isExerciseTimerRunning, isTimeBased, exerciseTimer]);

  useEffect(() => {
    // Reset exercise timer when exercise/set changes
    if (isTimeBased) {
      setExerciseTimer(targetTimeSeconds);
      setIsExerciseTimerRunning(false);
    }
  }, [currentIndex, currentSet, isTimeBased, targetTimeSeconds]);

  const handleNextSet = () => {
    if (currentSet < currentExercise.sets) {
      setCurrentSet(c => c + 1);
    } else {
      // Exercise Complete
      if (currentIndex < exercises.length - 1) {
        setCurrentIndex(c => c + 1);
        setCurrentSet(1);
      } else {
        // Workout Complete
        setIsActive(false);
        onComplete(Math.ceil(timer / 60));
      }
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const progress = ((currentIndex) / exercises.length) * 100;

  return (
    <div className="fixed inset-0 z-50 bg-slate-950 flex flex-col items-center justify-center p-4">
      {/* Background Ambience */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-0 left-0 w-full h-1/2 bg-gradient-to-b from-emerald-900/20 to-transparent"></div>
        <div className="absolute bottom-0 left-0 w-full h-1/2 bg-gradient-to-t from-black to-transparent"></div>
      </div>

      <div className="w-full max-w-2xl relative z-10 space-y-8">
        {/* Header */}
        <div className="flex items-center justify-between text-slate-400">
          <div className="text-sm font-medium">Time Elapsed: <span className="text-white font-mono text-lg">{formatTime(timer)}</span></div>
          <Button variant="ghost" onClick={onCancel} className="text-red-400 hover:text-red-300">Abort Quest</Button>
        </div>

        {/* Progress */}
        <div>
           <ProgressBar value={progress} max={100} label={`Exercise ${currentIndex + 1} of ${exercises.length}`} />
        </div>

        {/* Main Card */}
        <Card className="border-emerald-500/30 shadow-[0_0_50px_rgba(16,185,129,0.1)]">
          <div className="text-center py-8 space-y-6">
            <div>
              <h2 className="text-3xl font-rpg font-bold text-white mb-2">{currentExercise.name}</h2>
              <div className="text-emerald-400 text-lg font-medium">
                Set {currentSet} / {currentExercise.sets}
              </div>
            </div>

            <div className="bg-slate-900/50 rounded-2xl p-8 border border-slate-700 mx-auto w-fit min-w-[200px]">
              {isTimeBased ? (
                <div className="space-y-4">
                  <div className={`text-5xl font-mono font-bold ${exerciseTimer < 10 && exerciseTimer > 0 ? 'text-red-500 animate-pulse' : 'text-white'}`}>
                    {formatTime(exerciseTimer)}
                  </div>
                  <div className="flex gap-2 justify-center">
                    <button 
                      onClick={() => setIsExerciseTimerRunning(!isExerciseTimerRunning)}
                      className="p-3 bg-slate-700 rounded-full hover:bg-slate-600 text-white transition-colors"
                    >
                      {isExerciseTimerRunning ? <Pause className="w-6 h-6"/> : <Play className="w-6 h-6"/>}
                    </button>
                    <button 
                       onClick={() => {
                         setIsExerciseTimerRunning(false);
                         setExerciseTimer(targetTimeSeconds);
                       }}
                       className="p-3 bg-slate-700 rounded-full hover:bg-slate-600 text-white transition-colors"
                    >
                      <RotateCcw className="w-6 h-6"/>
                    </button>
                  </div>
                </div>
              ) : (
                <div>
                   <div className="text-5xl font-bold text-white mb-2">{currentExercise.target}</div>
                   <div className="text-slate-400 uppercase tracking-widest text-sm">Reps</div>
                </div>
              )}
            </div>

            <div className="pt-4">
              <Button 
                onClick={handleNextSet}
                className="w-full max-w-sm mx-auto py-4 text-lg bg-emerald-600 hover:bg-emerald-500"
              >
                {currentSet === currentExercise.sets && currentIndex === exercises.length - 1 ? (
                  <span className="flex items-center gap-2"><ShieldCheck /> Complete Quest</span>
                ) : (
                  <span className="flex items-center gap-2"><CheckCircle /> Complete Set</span>
                )}
              </Button>
            </div>
          </div>
        </Card>

        {/* Up Next */}
        {currentIndex < exercises.length - 1 && (
          <div className="text-center text-slate-500 text-sm flex items-center justify-center gap-2">
            <span>Next:</span>
            <span className="text-slate-300 font-medium">{exercises[currentIndex + 1].name}</span>
            <ArrowRight className="w-4 h-4" />
          </div>
        )}
      </div>
    </div>
  );
};

