import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage } from '../types';
import { getCoachResponse } from '../services/gemini';
import { Card, Button } from '../components/Shared';
import { Send, User, Bot, Sparkles } from 'lucide-react';

interface CoachProps {
  user: UserProfile;
}

const QUICK_REPLIES = [
  "What should I train today?",
  "I feel tired, motivate me!",
  "How to improve my push-ups?",
  "Explain progressive overload."
];

export const Coach: React.FC<CoachProps> = ({ user }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: `Greetings, ${user.name}! I am your Iron Coach. How shall we strengthen your resolve today?`,
      timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (text: string = input) => {
    if (!text.trim()) return;

    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      text: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Convert internal ChatMessage to the history format expected by service
      const history = messages.concat(userMsg).map(m => ({ role: m.role, text: m.text }));
      const responseText = await getCoachResponse(history, user);

      const botMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col gap-4 animate-fade-in">
       <div className="flex items-center gap-3 mb-2">
         <div className="w-10 h-10 rounded-full bg-emerald-900 border border-emerald-500 flex items-center justify-center">
           <Bot className="w-6 h-6 text-emerald-400" />
         </div>
         <div>
           <h2 className="text-xl font-rpg font-bold text-white">Coach Assistant</h2>
           <p className="text-xs text-emerald-400 flex items-center gap-1">
             <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
             Online
           </p>
         </div>
       </div>

       <Card className="flex-1 flex flex-col overflow-hidden bg-slate-900/50 border-slate-700">
         <div className="flex-1 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
            {messages.map((msg) => (
              <div 
                key={msg.id} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`
                  max-w-[80%] rounded-2xl p-4 text-sm leading-relaxed
                  ${msg.role === 'user' 
                    ? 'bg-emerald-600 text-white rounded-br-none' 
                    : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-bl-none'}
                `}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-slate-800 border border-slate-700 rounded-2xl rounded-bl-none p-4 flex gap-1">
                  <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce"></span>
                  <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-100"></span>
                  <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-200"></span>
                </div>
              </div>
            )}
         </div>

         {/* Quick Replies */}
         <div className="p-2 flex gap-2 overflow-x-auto border-t border-slate-800 bg-slate-900/80 scrollbar-hide">
            {QUICK_REPLIES.map(reply => (
              <button
                key={reply}
                onClick={() => handleSend(reply)}
                className="whitespace-nowrap px-3 py-1.5 rounded-full bg-slate-800 border border-slate-700 text-xs text-slate-300 hover:bg-slate-700 hover:text-white transition-colors flex items-center gap-1"
              >
                <Sparkles className="w-3 h-3 text-quest-gold" />
                {reply}
              </button>
            ))}
         </div>

         {/* Input */}
         <div className="p-4 bg-slate-800 border-t border-slate-700">
           <form 
              onSubmit={(e) => { e.preventDefault(); handleSend(); }}
              className="flex gap-2"
           >
             <input
               type="text"
               value={input}
               onChange={(e) => setInput(e.target.value)}
               placeholder="Ask your coach..."
               className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:border-emerald-500 outline-none"
             />
             <Button type="submit" disabled={!input.trim() || isTyping}>
               <Send className="w-4 h-4" />
             </Button>
           </form>
         </div>
       </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './views/Dashboard';
import { CustomWorkout } from './views/CustomWorkout';
import { ActiveSession } from './views/ActiveSession';
import { AIGenerator } from './views/AIGenerator';
import { Coach } from './views/Coach';
import { Character } from './views/Character';
import { Card } from './components/Shared';
import { 
  AppState, 
  ViewState, 
  INITIAL_USER, 
  Exercise, 
  WorkoutSession 
} from './types';
import { loadGameData, saveGameData } from './services/storage';
import { Menu, Calendar as CalendarIcon, Trophy, Settings } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

function App() {
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [data, setData] = useState<AppState | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Initialize Data
  useEffect(() => {
    const loadedData = loadGameData();
    setData(loadedData);
  }, []);

  // Auto-Save
  useEffect(() => {
    if (data) {
      saveGameData(data);
    }
  }, [data]);

  if (!data) return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-white">Loading Quest...</div>;

  const handleUpdateUser = (updates: Partial<typeof data.user>) => {
    setData(prev => prev ? { ...prev, user: { ...prev.user, ...updates } } : null);
  };

  const handleUpdateExercises = (exercises: Exercise[]) => {
    setData(prev => prev ? { ...prev, customRoutine: exercises } : null);
  };

  const handleWorkoutComplete = (duration: number) => {
    if (!data) return;

    // XP Calculation: Base 100 + 10 per minute
    const xpEarned = 100 + (duration * 5);
    let newXp = data.user.currentXp + xpEarned;
    let newLevel = data.user.level;

    // Level Up Logic
    if (newXp >= data.user.maxXp) {
      newXp = newXp - data.user.maxXp;
      newLevel += 1;
      alert("LEVEL UP! You feel stronger!");
    }

    const session: WorkoutSession = {
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
      name: "Custom Quest",
      exercises: data.customRoutine,
      durationMinutes: duration,
      xpEarned
    };

    const newHistory = [session, ...data.history];

    const today = new Date().toISOString().split('T')[0];
    const lastDate = data.user.lastWorkoutDate ? data.user.lastWorkoutDate.split('T')[0] : null;
    let newStreak = data.user.streak;

    if (lastDate !== today) {
       // Simple streak logic (consecutive days check omitted for brevity, just increments on unique days)
       newStreak += 1;
    }

    setData({
      ...data,
      user: {
        ...data.user,
        level: newLevel,
        currentXp: newXp,
        maxXp: newLevel * 100, // Scaling difficulty
        totalWorkouts: data.user.totalWorkouts + 1,
        totalTimeMinutes: data.user.totalTimeMinutes + duration,
        streak: newStreak,
        lastWorkoutDate: new Date().toISOString(),
        stats: {
           ...data.user.stats,
           strength: data.user.stats.strength + 1,
           endurance: data.user.stats.endurance + (duration > 20 ? 1 : 0),
           consistency: data.user.stats.consistency + 1
        }
      },
      history: newHistory,
      dailyQuest: { ...data.dailyQuest, completed: true }
    });

    setView('DASHBOARD');
  };

  const renderContent = () => {
    switch (view) {
      case 'DASHBOARD':
        return <Dashboard 
          user={data.user} 
          dailyQuest={data.dailyQuest} 
          onStartWorkout={() => setView('CUSTOM_WORKOUT')}
        />;
      case 'CHARACTER':
        return <Character user={data.user} />;
      case 'CUSTOM_WORKOUT':
        return <CustomWorkout 
          exercises={data.customRoutine} 
          setExercises={handleUpdateExercises}
          onStartSession={() => setView('ACTIVE_SESSION')}
        />;
      case 'ACTIVE_SESSION':
        return <ActiveSession 
          exercises={data.customRoutine}
          onComplete={handleWorkoutComplete}
          onCancel={() => setView('CUSTOM_WORKOUT')}
        />;
      case 'AI_GENERATOR':
        return <AIGenerator 
           onPlanGenerated={(plan) => {
             handleUpdateExercises(plan);
             setView('CUSTOM_WORKOUT');
           }}
        />;
      case 'COACH':
        return <Coach user={data.user} />;
      case 'PROGRESS':
        return (
          <div className="space-y-6 animate-fade-in">
             <h2 className="text-3xl font-rpg font-bold text-white">Quest Log</h2>
             <Card title="Workout History">
               <div className="h-64">
                 <ResponsiveContainer width="100%" height="100%">
                   <LineChart data={data.history.slice().reverse().map((h, i) => ({ name: i, duration: h.durationMinutes }))}>
                     <XAxis dataKey="name" stroke="#475569" />
                     <YAxis stroke="#475569" />
                     <Tooltip contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155' }} />
                     <Line type="monotone" dataKey="duration" stroke="#10b981" strokeWidth={2} />
                   </LineChart>
                 </ResponsiveContainer>
               </div>
             </Card>
             <div className="space-y-2">
               {data.history.map(session => (
                 <div key={session.id} className="bg-slate-800 p-4 rounded-lg border border-slate-700 flex justify-between items-center">
                   <div>
                     <p className="font-bold text-white">{new Date(session.date).toLocaleDateString()}</p>
                     <p className="text-sm text-slate-400">{session.name}</p>
                   </div>
                   <div className="text-emerald-400 font-mono">+{session.xpEarned} XP</div>
                 </div>
               ))}
             </div>
          </div>
        );
      case 'CALENDAR':
         return (
            <div className="animate-fade-in text-center py-20">
               <CalendarIcon className="w-16 h-16 text-slate-600 mx-auto mb-4" />
               <h2 className="text-2xl font-bold text-white">Calendar</h2>
               <p className="text-slate-400">Coming soon in the next expansion.</p>
            </div>
         );
       case 'INVENTORY':
         return (
            <div className="animate-fade-in text-center py-20">
               <Trophy className="w-16 h-16 text-slate-600 mx-auto mb-4" />
               <h2 className="text-2xl font-bold text-white">Inventory</h2>
               <p className="text-slate-400">Coming soon in the next expansion.</p>
            </div>
         );
       case 'QUESTS':
         return (
             <div className="animate-fade-in text-center py-20">
               <h2 className="text-2xl font-bold text-white">Daily Quests</h2>
               <p className="text-slate-400">More quests unlocking at Level 5.</p>
            </div>
         );
       case 'SETTINGS':
          return (
             <div className="animate-fade-in space-y-6">
                <h2 className="text-2xl font-bold text-white">Settings</h2>
                <Card>
                  <div className="space-y-4">
                     <button 
                       onClick={() => {
                         if(confirm("Reset all progress? This cannot be undone.")) {
                            localStorage.clear();
                            window.location.reload();
                         }
                       }}
                       className="w-full p-3 bg-red-900/50 text-red-400 border border-red-900 rounded hover:bg-red-900 transition-colors"
                     >
                        Reset Progress
                     </button>
                  </div>
                </Card>
             </div>
          );
      default:
        return <div>View not found</div>;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans flex overflow-hidden">
      <Sidebar 
        currentView={view} 
        setView={setView} 
        isMobileOpen={isMobileMenuOpen}
        setIsMobileOpen={setIsMobileMenuOpen}
      />

      <main className="flex-1 overflow-y-auto h-screen relative">
        <header className="lg:hidden h-16 border-b border-slate-800 flex items-center px-4 justify-between bg-slate-950/90 backdrop-blur sticky top-0 z-20">
          <span className="font-rpg font-bold text-quest-gold">IRON QUEST</span>
          <button onClick={() => setIsMobileMenuOpen(true)} className="p-2 text-slate-300">
            <Menu />
          </button>
        </header>

        <div className="p-4 lg:p-8 max-w-6xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

