import React, { useState, useEffect, useRef } from 'react';
import { Exercise, ExerciseType, Language } from '../types';
import { Card, Button, ProgressBar } from '../components/Shared';
import { Play, Pause, RotateCcw, CheckCircle, ArrowRight, ShieldCheck, X } from 'lucide-react';
import { getExerciseInfo } from '../data/exercises';
import { TRANSLATIONS } from '../data/translations';

interface ActiveSessionProps {
  exercises: Exercise[];
  onComplete: (durationMinutes: number) => void;
  onCancel: () => void;
  language: Language;
}

export const ActiveSession: React.FC<ActiveSessionProps> = ({ exercises, onComplete, onCancel, language }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [currentSet, setCurrentSet] = useState(1);
  const [timer, setTimer] = useState(0); // For workout duration
  const [isActive, setIsActive] = useState(true);

  // Exercise Timer (for MINUTES type)
  const [exerciseTimer, setExerciseTimer] = useState(0);
  const [isExerciseTimerRunning, setIsExerciseTimerRunning] = useState(false);
  const [showAnimation, setShowAnimation] = useState(false);

  const t = TRANSLATIONS[language];
  const currentExercise = exercises[currentIndex];
  const exerciseInfo = getExerciseInfo(currentExercise.name);
  const isTimeBased = currentExercise.type === 'MINUTES';
  const targetTimeSeconds = isTimeBased ? currentExercise.target * 60 : 0;

  useEffect(() => {
    let interval: any;
    if (isActive) {
      interval = setInterval(() => {
        setTimer(t => t + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isActive]);

  // Exercise Timer Logic
  useEffect(() => {
    let interval: any;
    if (isExerciseTimerRunning && isTimeBased && exerciseTimer > 0) {
      interval = setInterval(() => {
        setExerciseTimer(t => {
          if (t <= 1) {
            setIsExerciseTimerRunning(false);
            return 0;
          }
          return t - 1;
        });
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isExerciseTimerRunning, isTimeBased, exerciseTimer]);

  useEffect(() => {
    // Reset exercise timer when exercise/set changes
    if (isTimeBased) {
      setExerciseTimer(targetTimeSeconds);
      setIsExerciseTimerRunning(false); // Do not auto start to let user prepare
    }
  }, [currentIndex, currentSet, isTimeBased, targetTimeSeconds]);

  const triggerCelebration = () => {
    setShowAnimation(true);
    setTimeout(() => setShowAnimation(false), 1000);
  };

  const handleNextSet = () => {
    triggerCelebration();
    if (currentSet < currentExercise.sets) {
      setCurrentSet(c => c + 1);
    } else {
      // Exercise Complete
      if (currentIndex < exercises.length - 1) {
        setCurrentIndex(c => c + 1);
        setCurrentSet(1);
      } else {
        // Workout Complete
        setIsActive(false);
        onComplete(Math.ceil(timer / 60));
      }
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const progress = ((currentIndex) / exercises.length) * 100;

  // Construct YouTube URL with parameters to fix embed issues and loop
  const videoId = exerciseInfo?.videoId || 'IODxDxX7oi4';
  // Use nocookie domain for better embed support, playlist param required for loop
  const embedUrl = `https://www.youtube-nocookie.com/embed/${videoId}?autoplay=1&mute=1&controls=0&loop=1&playlist=${videoId}&modestbranding=1&rel=0`;

  const exerciseName = language === 'id' && exerciseInfo?.nameId ? exerciseInfo.nameId : currentExercise.name;

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col">
      {/* Animations Overlay */}
      {showAnimation && (
        <div className="absolute inset-0 pointer-events-none z-[60] flex items-center justify-center overflow-hidden">
          <div className="w-full h-full absolute bg-quest-primary/20 animate-pulse"></div>
          <div className="text-6xl font-bold text-quest-gold animate-bounce drop-shadow-[0_0_20px_rgba(251,191,36,0.8)]">
            {language === 'id' ? 'MANTAP!' : 'GREAT!'}
          </div>
        </div>
      )}

      {/* Top Half: Video Player */}
      <div className="relative h-[40vh] md:h-[50vh] w-full bg-slate-900 border-b-4 border-quest-primary shadow-[0_0_50px_rgba(6,182,212,0.2)]">
        {exerciseInfo ? (
          <iframe 
            src={embedUrl} 
            title={currentExercise.name}
            className="w-full h-full object-cover"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            referrerPolicy="no-referrer"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center text-slate-500">
             Video Signal Lost
          </div>
        )}

        {/* Overlay Info on Video */}
        <div className="absolute top-0 left-0 w-full p-4 bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
          <div className="flex justify-between items-start">
             <div>
               <h2 className="text-3xl font-display font-bold text-white drop-shadow-md">{exerciseName}</h2>
               <div className="flex gap-2 mt-1">
                 <span className="px-2 py-0.5 bg-quest-primary text-black text-xs font-bold rounded">
                    SET {currentSet} / {currentExercise.sets}
                 </span>
                 <span className="px-2 py-0.5 bg-black/50 border border-white/20 text-white text-xs font-bold rounded">
                    {language === 'id' && exerciseInfo?.nameId ? exerciseInfo.name : ''}
                 </span>
               </div>
             </div>
             <button onClick={onCancel} className="pointer-events-auto p-2 bg-red-600/80 hover:bg-red-500 text-white rounded-full">
               <X className="w-6 h-6" />
             </button>
          </div>
        </div>
      </div>

      {/* Bottom Half: Controls */}
      <div className="flex-1 bg-quest-bg relative flex flex-col p-4 md:p-8 overflow-hidden">
        {/* Ambient Glow */}
        <div className="absolute inset-0 bg-gradient-to-t from-quest-primary/5 to-transparent animate-pulse-slow"></div>

        {/* Global Timer & Progress */}
        <div className="flex justify-between items-center mb-4 relative z-10 text-slate-400 text-sm font-mono">
           <span>{t.timeElapsed}: <span className="text-white">{formatTime(timer)}</span></span>
           <span>{currentIndex + 1} / {exercises.length}</span>
        </div>
        <div className="relative z-10 mb-8">
           <ProgressBar value={progress} max={100} showText={false} color="bg-quest-primary" />
        </div>

        {/* Main Interaction Area */}
        <div className="flex-1 flex flex-col items-center justify-center relative z-10 gap-8">

            {/* Rep Counter or Timer */}
            <div className={`
              relative w-48 h-48 md:w-56 md:h-56 rounded-full border-4 flex items-center justify-center shadow-[0_0_30px_rgba(6,182,212,0.1)]
              ${isTimeBased && isExerciseTimerRunning ? 'border-quest-accent animate-pulse shadow-[0_0_50px_rgba(244,63,94,0.4)]' : 'border-quest-border'}
            `}>
              {isTimeBased ? (
                <div className="text-center">
                  <div className={`text-6xl font-mono font-bold ${exerciseTimer < 10 && exerciseTimer > 0 ? 'text-red-500 animate-ping' : 'text-white'}`}>
                    {formatTime(exerciseTimer)}
                  </div>
                  <div className="flex gap-4 justify-center mt-4">
                    <button 
                      onClick={() => setIsExerciseTimerRunning(!isExerciseTimerRunning)}
                      className="p-3 bg-quest-card border border-quest-border rounded-full hover:bg-quest-primary hover:text-black transition-all"
                    >
                      {isExerciseTimerRunning ? <Pause className="w-6 h-6"/> : <Play className="w-6 h-6"/>}
                    </button>
                    <button 
                       onClick={() => {
                         setIsExerciseTimerRunning(false);
                         setExerciseTimer(targetTimeSeconds);
                       }}
                       className="p-3 bg-quest-card border border-quest-border rounded-full hover:text-white transition-colors"
                    >
                      <RotateCcw className="w-6 h-6"/>
                    </button>
                  </div>
                </div>
              ) : (
                <div className="text-center">
                   <div className="text-7xl font-bold text-white mb-2 drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">{currentExercise.target}</div>
                   <div className="text-quest-primary uppercase tracking-widest text-lg font-bold">{t.reps}</div>
                </div>
              )}
            </div>

            {/* Complete Button */}
            <Button 
              onClick={handleNextSet}
              className={`
                w-full max-w-md py-5 text-xl tracking-widest font-bold shadow-[0_0_20px_rgba(16,185,129,0.3)]
                transition-transform hover:scale-105 active:scale-95
              `}
              variant="primary"
              style={{ backgroundColor: '#10b981', color: 'white' }}
            >
              {currentSet === currentExercise.sets && currentIndex === exercises.length - 1 ? (
                <span className="flex items-center gap-2"><ShieldCheck className="w-6 h-6" /> {t.completeQuest}</span>
              ) : (
                <span className="flex items-center gap-2"><CheckCircle className="w-6 h-6" /> {t.completeSet}</span>
              )}
            </Button>
        </div>

        {/* Next Exercise Preview */}
        {currentIndex < exercises.length - 1 && (
           <div className="mt-auto pt-4 text-center text-slate-500 text-sm flex items-center justify-center gap-2 relative z-10">
            <span>{t.next}</span>
            <span className="text-quest-primary font-medium">
               {language === 'id' && getExerciseInfo(exercises[currentIndex+1].name)?.nameId ? getExerciseInfo(exercises[currentIndex+1].name)?.nameId : exercises[currentIndex + 1].name}
            </span>
            <ArrowRight className="w-4 h-4" />
          </div>
        )}
      </div>
    </div>
  );
};

