import React, { useState } from 'react';
import { Exercise, ExerciseType } from '../types';
import { Card, Button } from '../components/Shared';
import { Trash2, Plus, Play, Dumbbell, Timer, Info } from 'lucide-react';
import { getExerciseInfo } from '../data/exercises';
import { ExerciseModal } from '../components/ExerciseModal';
import { TRANSLATIONS } from '../data/translations';

interface CustomWorkoutProps {
  exercises: Exercise[];
  setExercises: (exercises: Exercise[]) => void;
  onStartSession: () => void;
  language: 'en' | 'id';
}

export const CustomWorkout: React.FC<CustomWorkoutProps> = ({ exercises, setExercises, onStartSession, language }) => {
  const [newExercise, setNewExercise] = useState<Partial<Exercise>>({
    name: '',
    type: 'REPS',
    target: 10,
    sets: 3
  });

  const t = TRANSLATIONS[language];
  const [modalInfo, setModalInfo] = useState<any>(null);

  const handleAddExercise = () => {
    if (!newExercise.name || !newExercise.target || !newExercise.sets) return;

    const exercise: Exercise = {
      id: crypto.randomUUID(),
      name: newExercise.name,
      type: newExercise.type as ExerciseType,
      target: Number(newExercise.target),
      sets: Number(newExercise.sets),
    };

    setExercises([...exercises, exercise]);
    setNewExercise({ name: '', type: 'REPS', target: 10, sets: 3 });
  };

  const handleRemoveExercise = (id: string) => {
    setExercises(exercises.filter(e => e.id !== id));
  };

  const handleShowInfo = (name: string) => {
    const info = getExerciseInfo(name);
    if (info) {
      setModalInfo(info);
    } else {
      // Fallback
      setModalInfo({
        name: name,
        description: language === 'id' ? "Ikuti gerakan dengan postur yang benar." : "Standard exercise execution. Ensure maintain proper posture.",
        videoId: "IODxDxX7oi4", // Default
        difficulty: "General",
        muscleGroup: "General"
      });
    }
  };

  const canStart = exercises.length >= 5;

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex items-center justify-between">
        <div>
           <h2 className="text-2xl font-display font-bold text-white">{t.customWorkout}</h2>
           <p className="text-slate-400 text-sm">{language === 'id' ? 'Rancang sendiri siksaanmu.' : 'Design your training regimen.'}</p>
        </div>
        <div className="text-quest-primary text-sm font-mono border border-quest-primary/30 px-3 py-1 rounded bg-quest-primary/5">
          {exercises.length} / 5 REQUIRED
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Form */}
        <Card title={t.addExercise} className="lg:col-span-1 h-fit">
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">{t.exerciseName}</label>
              <div className="flex gap-2">
                 <input 
                  type="text" 
                  value={newExercise.name}
                  onChange={(e) => setNewExercise({...newExercise, name: e.target.value})}
                  className="w-full bg-quest-bg border border-quest-border rounded-lg p-2 text-white focus:border-quest-primary outline-none text-sm"
                  placeholder={language === 'id' ? 'Contoh: Push Ups' : 'e.g. Push Ups'}
                />
                {newExercise.name && (
                   <button 
                     onClick={() => handleShowInfo(newExercise.name!)}
                     className="p-2 bg-quest-bg border border-quest-border rounded-lg text-quest-primary hover:text-white hover:bg-quest-primary transition-colors"
                     title="View Info"
                   >
                     <Info className="w-5 h-5" />
                   </button>
                )}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Type</label>
                <div className="flex bg-quest-bg rounded-lg p-1 border border-quest-border">
                  <button 
                    onClick={() => setNewExercise({...newExercise, type: 'REPS'})}
                    className={`flex-1 text-xs py-1.5 rounded transition-colors ${newExercise.type === 'REPS' ? 'bg-quest-card text-white shadow' : 'text-slate-500'}`}
                  >
                    {t.reps}
                  </button>
                  <button 
                    onClick={() => setNewExercise({...newExercise, type: 'MINUTES'})}
                    className={`flex-1 text-xs py-1.5 rounded transition-colors ${newExercise.type === 'MINUTES' ? 'bg-quest-card text-white shadow' : 'text-slate-500'}`}
                  >
                    {t.mins}
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">{t.sets}</label>
                <input 
                  type="number" 
                  min="1"
                  max="10"
                  value={newExercise.sets}
                  onChange={(e) => setNewExercise({...newExercise, sets: parseInt(e.target.value)})}
                  className="w-full bg-quest-bg border border-quest-border rounded-lg p-2 text-white outline-none text-sm"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                {newExercise.type === 'REPS' ? t.reps : t.minutes}
              </label>
              <input 
                type="number" 
                min="1"
                value={newExercise.target}
                onChange={(e) => setNewExercise({...newExercise, target: parseInt(e.target.value)})}
                className="w-full bg-quest-bg border border-quest-border rounded-lg p-2 text-white outline-none text-sm"
              />
            </div>

            <Button onClick={handleAddExercise} className="w-full" disabled={!newExercise.name}>
              <Plus className="w-4 h-4" /> {t.addExercise}
            </Button>
          </div>
        </Card>

        {/* List */}
        <div className="lg:col-span-2 space-y-4">
          {exercises.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 border-2 border-dashed border-quest-border rounded-xl text-slate-600">
              <Dumbbell className="w-12 h-12 mb-4 opacity-20" />
              <p>{language === 'id' ? 'Daftar Kosong.' : 'Sequence Empty.'}</p>
              <p className="text-sm">{language === 'id' ? 'Mulai tambah latihan!' : 'Initialize exercises to build routine.'}</p>
            </div>
          ) : (
            <div className="space-y-2">
              {exercises.map((ex, idx) => {
                const exName = language === 'id' && getExerciseInfo(ex.name)?.nameId ? getExerciseInfo(ex.name)?.nameId : ex.name;
                return (
                  <div key={ex.id} className="bg-quest-card border border-quest-border p-4 rounded-lg flex items-center justify-between group hover:border-quest-primary/50 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className="w-8 h-8 rounded-full bg-quest-bg flex items-center justify-center text-slate-400 font-bold text-sm border border-quest-border">
                        {idx + 1}
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                           <h4 className="font-bold text-white">{exName}</h4>
                           <button onClick={() => handleShowInfo(ex.name)} className="text-quest-primary hover:text-white transition-colors">
                              <Info className="w-4 h-4" />
                           </button>
                        </div>
                        <div className="flex gap-4 text-xs text-slate-400 mt-1">
                          <span className="flex items-center gap-1">
                            {ex.type === 'REPS' ? <Dumbbell className="w-3 h-3"/> : <Timer className="w-3 h-3"/>}
                            {ex.target} {ex.type === 'REPS' ? t.reps : t.mins}
                          </span>
                          <span>{ex.sets} {t.sets}</span>
                        </div>
                      </div>
                    </div>
                    <button 
                      onClick={() => handleRemoveExercise(ex.id)}
                      className="p-2 text-slate-500 hover:text-rose-500 transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })}
            </div>
          )}

          <div className="mt-8 pt-6 border-t border-quest-border">
            <Button 
              onClick={onStartSession} 
              disabled={!canStart} 
              className={`w-full py-4 text-lg ${canStart ? 'animate-pulse shadow-[0_0_20px_rgba(6,182,212,0.4)]' : ''}`}
            >
              <Play className="w-5 h-5" />
              {canStart ? t.startSession : `Add ${5 - exercises.length} more modules to execute`}
            </Button>
          </div>
        </div>
      </div>

      <ExerciseModal 
        isOpen={!!modalInfo} 
        info={modalInfo} 
        onClose={() => setModalInfo(null)}
        language={language}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './views/Dashboard';
import { CustomWorkout } from './views/CustomWorkout';
import { ActiveSession } from './views/ActiveSession';
import { AIGenerator } from './views/AIGenerator';
import { Coach } from './views/Coach';
import { Profile } from './views/Profile';
import { Onboarding } from './views/Onboarding';
import { Card } from './components/Shared';
import { 
  AppState, 
  ViewState, 
  Exercise, 
  WorkoutSession,
  Language 
} from './types';
import { loadGameData, saveGameData } from './services/storage';
import { Menu, Calendar as CalendarIcon, Trophy } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

function App() {
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [data, setData] = useState<AppState | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Initialize Data
  useEffect(() => {
    const loadedData = loadGameData();
    // Check if new user
    if (!loadedData.user.name) {
      setView('ONBOARDING');
    }
    setData(loadedData);
  }, []);

  // Auto-Save
  useEffect(() => {
    if (data) {
      saveGameData(data);
    }
  }, [data]);

  if (!data) return <div className="min-h-screen bg-black flex items-center justify-center text-white font-mono">INITIALIZING SYSTEM...</div>;

  const handleUpdateUser = (updates: Partial<typeof data.user>) => {
    setData(prev => prev ? { ...prev, user: { ...prev.user, ...updates } } : null);
  };

  const handleUpdateExercises = (exercises: Exercise[]) => {
    setData(prev => prev ? { ...prev, customRoutine: exercises } : null);
  };

  const handleOnboardingComplete = (profile: Partial<typeof data.user>) => {
    handleUpdateUser(profile);
    setView('DASHBOARD');
  };

  const handleSetLanguage = (lang: Language) => {
    handleUpdateUser({ language: lang });
  }

  const handleWorkoutComplete = (duration: number) => {
    if (!data) return;

    // XP Calculation
    const xpEarned = 100 + (duration * 5);
    let newXp = data.user.currentXp + xpEarned;
    let newLevel = data.user.level;

    // Level Up Logic
    if (newXp >= data.user.maxXp) {
      newXp = newXp - data.user.maxXp;
      newLevel += 1;
      alert(data.user.language === 'id' ? "LEVEL NAIK! MAKIN KUAT!" : "LEVEL INCREASED. STATS UPGRADED.");
    }

    const session: WorkoutSession = {
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
      name: "Custom Protocol",
      exercises: data.customRoutine,
      durationMinutes: duration,
      xpEarned
    };

    const newHistory = [session, ...data.history];

    const today = new Date().toISOString().split('T')[0];
    const lastDate = data.user.lastWorkoutDate ? data.user.lastWorkoutDate.split('T')[0] : null;
    let newStreak = data.user.streak;

    if (lastDate !== today) {
       newStreak += 1;
    }

    setData({
      ...data,
      user: {
        ...data.user,
        level: newLevel,
        currentXp: newXp,
        maxXp: newLevel * 100, 
        totalWorkouts: data.user.totalWorkouts + 1,
        totalTimeMinutes: data.user.totalTimeMinutes + duration,
        streak: newStreak,
        lastWorkoutDate: new Date().toISOString(),
        stats: {
           ...data.user.stats,
           strength: data.user.stats.strength + 1,
           endurance: data.user.stats.endurance + (duration > 20 ? 1 : 0),
           consistency: data.user.stats.consistency + 1
        }
      },
      history: newHistory,
      dailyQuest: { ...data.dailyQuest, completed: true }
    });

    setView('DASHBOARD');
  };

  if (view === 'ONBOARDING') {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const currentLang = data.user.language || 'en';

  const renderContent = () => {
    switch (view) {
      case 'DASHBOARD':
        return <Dashboard 
          user={data.user} 
          dailyQuest={data.dailyQuest} 
          onStartWorkout={() => setView('CUSTOM_WORKOUT')}
        />;
      case 'PROFILE':
        return <Profile user={data.user} onUpdate={handleUpdateUser} />;
      case 'CUSTOM_WORKOUT':
        return <CustomWorkout 
          exercises={data.customRoutine} 
          setExercises={handleUpdateExercises}
          onStartSession={() => setView('ACTIVE_SESSION')}
          language={currentLang}
        />;
      case 'ACTIVE_SESSION':
        return <ActiveSession 
          exercises={data.customRoutine}
          onComplete={handleWorkoutComplete}
          onCancel={() => setView('CUSTOM_WORKOUT')}
          language={currentLang}
        />;
      case 'AI_GENERATOR':
        return <AIGenerator 
           onPlanGenerated={(plan) => {
             handleUpdateExercises(plan);
             setView('CUSTOM_WORKOUT');
           }}
        />;
      case 'COACH':
        return <Coach user={data.user} />;
      case 'PROGRESS':
        return (
          <div className="space-y-6 animate-fade-in">
             <h2 className="text-3xl font-display font-bold text-white">Data Log</h2>
             <Card title="Activity Analysis">
               <div className="h-64">
                 <ResponsiveContainer width="100%" height="100%">
                   <LineChart data={data.history.slice().reverse().map((h, i) => ({ name: i, duration: h.durationMinutes }))}>
                     <XAxis dataKey="name" stroke="#475569" />
                     <YAxis stroke="#475569" />
                     <Tooltip contentStyle={{ backgroundColor: '#18181b', borderColor: '#27272a' }} />
                     <Line type="monotone" dataKey="duration" stroke="#06b6d4" strokeWidth={2} dot={{r: 4, fill: '#06b6d4'}} />
                   </LineChart>
                 </ResponsiveContainer>
               </div>
             </Card>
             <div className="space-y-2">
               {data.history.map(session => (
                 <div key={session.id} className="bg-quest-card p-4 rounded-lg border border-quest-border flex justify-between items-center">
                   <div>
                     <p className="font-bold text-white">{new Date(session.date).toLocaleDateString()}</p>
                     <p className="text-sm text-slate-400">{session.name}</p>
                   </div>
                   <div className="text-quest-primary font-mono">+{session.xpEarned} XP</div>
                 </div>
               ))}
             </div>
          </div>
        );
      case 'CALENDAR':
         return (
            <div className="animate-fade-in text-center py-20">
               <CalendarIcon className="w-16 h-16 text-slate-700 mx-auto mb-4" />
               <h2 className="text-2xl font-bold text-white">Schedule Locked</h2>
               <p className="text-slate-500">Feature available in next patch.</p>
            </div>
         );
       case 'INVENTORY':
         return (
            <div className="animate-fade-in text-center py-20">
               <Trophy className="w-16 h-16 text-slate-700 mx-auto mb-4" />
               <h2 className="text-2xl font-bold text-white">Inventory Locked</h2>
               <p className="text-slate-500">Feature available in next patch.</p>
            </div>
         );
       case 'QUESTS':
         return (
             <div className="animate-fade-in text-center py-20">
               <h2 className="text-2xl font-bold text-white">Mission Log</h2>
               <p className="text-slate-500">Additional missions unlocking at Level 5.</p>
            </div>
         );
       case 'SETTINGS':
          return (
             <div className="animate-fade-in space-y-6">
                <h2 className="text-2xl font-bold text-white">System Settings</h2>
                <Card>
                  <div className="space-y-4">
                     <button 
                       onClick={() => {
                         if(confirm("Factory Reset? This action is irreversible.")) {
                            localStorage.clear();
                            window.location.reload();
                         }
                       }}
                       className="w-full p-3 bg-rose-900/20 text-rose-500 border border-rose-900/50 rounded hover:bg-rose-900/40 transition-colors"
                     >
                        Factory Reset
                     </button>
                  </div>
                </Card>
             </div>
          );
      default:
        return <div>View not found</div>;
    }
  };

  return (
    <div className="min-h-screen bg-quest-bg text-slate-200 font-sans flex overflow-hidden">
      <Sidebar 
        currentView={view} 
        setView={setView} 
        isMobileOpen={isMobileMenuOpen}
        setIsMobileOpen={setIsMobileMenuOpen}
        language={currentLang}
        setLanguage={handleSetLanguage}
      />

      <main className="flex-1 overflow-y-auto h-screen relative">
        <header className="lg:hidden h-16 border-b border-quest-border flex items-center px-4 justify-between bg-quest-bg/90 backdrop-blur sticky top-0 z-20">
          <span className="font-display font-bold text-white tracking-widest">IRON<span className="text-quest-primary">QUEST</span></span>
          <button onClick={() => setIsMobileMenuOpen(true)} className="p-2 text-slate-300">
            <Menu />
          </button>
        </header>

        <div className="p-4 lg:p-8 max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

export default App;

